fn parse_storage_timestamp_millis(timestamp: &str) -> Option<i64> {
    let normalized = timestamp.trim();
    if normalized.is_empty() {
        return None;
    }

    let numeric = normalized.strip_prefix('-').unwrap_or(normalized);
    if !numeric.is_empty() && numeric.chars().all(|character| character.is_ascii_digit()) {
        let parsed = normalized.parse::<i128>().ok()?;
        let absolute = parsed.abs();
        let milliseconds = if absolute >= 1_000_000_000_000_000_000 {
            parsed / 1_000_000
        } else if absolute >= 1_000_000_000_000_000 {
            parsed / 1_000
        } else if absolute >= 1_000_000_000_000 {
            parsed
        } else if absolute >= 1_000_000_000 {
            parsed * 1_000
        } else {
            parsed
        };

        return i64::try_from(milliseconds).ok();
    }

    let parsed =
        time::OffsetDateTime::parse(normalized, &time::format_description::well_known::Rfc3339)
            .ok()?;
    Some((parsed.unix_timestamp_nanos() / 1_000_000) as i64)
}

fn storage_timestamp_from_millis(value: i64) -> String {
    let seconds = value.div_euclid(1_000);
    let milliseconds = value.rem_euclid(1_000) as u16;
    let datetime = time::OffsetDateTime::from_unix_timestamp(seconds)
        .unwrap_or(time::OffsetDateTime::UNIX_EPOCH)
        .replace_millisecond(milliseconds)
        .unwrap_or(time::OffsetDateTime::UNIX_EPOCH);
    datetime
        .format(&time::format_description::well_known::Rfc3339)
        .unwrap_or_else(|_| "1970-01-01T00:00:00Z".to_owned())
}

fn normalize_storage_timestamp_value(timestamp: &str) -> Option<String> {
    parse_storage_timestamp_millis(timestamp).map(storage_timestamp_from_millis)
}

fn normalize_optional_storage_timestamp_value(value: Option<String>) -> Option<String> {
    value.and_then(|timestamp| normalize_storage_timestamp_value(timestamp.as_str()))
}

fn resolve_latest_storage_timestamp_from_candidates(candidates: &[Option<&str>]) -> Option<String> {
    candidates
        .iter()
        .filter_map(|candidate| {
            candidate.and_then(|timestamp| {
                parse_storage_timestamp_millis(timestamp)
                    .map(|parsed| (parsed, timestamp.to_owned()))
            })
        })
        .max_by(|left, right| left.0.cmp(&right.0).then_with(|| left.1.cmp(&right.1)))
        .map(|(_, timestamp)| timestamp)
}

fn resolve_projection_transcript_updated_at(
    events: &[CodingSessionEventPayload],
) -> Option<String> {
    events
        .iter()
        .filter(|event| {
            event.kind == "message.completed"
                || event.kind == "message.delta"
                || event.kind == "message.deleted"
                || event.kind == "message.edited"
        })
        .filter_map(|event| {
            parse_storage_timestamp_millis(event.created_at.as_str())
                .map(|timestamp| (timestamp, event.created_at.clone()))
        })
        .max_by(|left, right| left.0.cmp(&right.0).then_with(|| left.1.cmp(&right.1)))
        .map(|(_, created_at)| created_at)
}

fn resolve_coding_session_payload_sort_timestamp(session: &CodingSessionPayload) -> i64 {
    if session.sort_timestamp > 0 {
        return session.sort_timestamp;
    }

    resolve_latest_storage_timestamp_from_candidates(&[
        session.transcript_updated_at.as_deref(),
        session.last_turn_at.as_deref(),
        Some(session.updated_at.as_str()),
        Some(session.created_at.as_str()),
    ])
    .as_deref()
    .and_then(parse_storage_timestamp_millis)
    .unwrap_or_default()
}

fn normalize_coding_session_payload(
    session: &CodingSessionPayload,
    transcript_updated_at: Option<String>,
    runtime_status: Option<String>,
) -> CodingSessionPayload {
    let resolved_transcript_updated_at =
        transcript_updated_at.or_else(|| session.transcript_updated_at.clone());
    let resolved_runtime_status = runtime_status.or_else(|| session.runtime_status.clone());
    let mut normalized = session.clone();
    normalized.transcript_updated_at = resolved_transcript_updated_at;
    normalized.runtime_status = resolved_runtime_status;
    normalized.sort_timestamp = resolve_coding_session_payload_sort_timestamp(&normalized);
    normalized
}

fn resolve_projection_runtime_status(events: &[CodingSessionEventPayload]) -> Option<String> {
    events
        .iter()
        .rev()
        .find_map(resolve_projection_event_runtime_status)
        .map(str::to_owned)
}

fn resolve_projection_event_runtime_status(
    event: &CodingSessionEventPayload,
) -> Option<&'static str> {
    let runtime_status = payload_string_ref(&event.payload, "runtimeStatus")
        .and_then(normalize_codeengine_runtime_status);

    match event.kind.as_str() {
        "turn.started" | "message.delta" => Some("streaming"),
        "approval.required" => runtime_status.or(Some("awaiting_approval")),
        "turn.completed" => Some("completed"),
        "turn.failed" => Some("failed"),
        "tool.call.requested" | "tool.call.progress" | "tool.call.completed" => {
            match runtime_status {
                Some(
                    "awaiting_approval" | "awaiting_user" | "awaiting_tool" | "failed"
                    | "terminated",
                ) => runtime_status,
                Some("streaming" | "initializing") => Some("streaming"),
                _ => None,
            }
        }
        "operation.updated" => runtime_status,
        "message.completed" => {
            let role = event_payload_role(&event.payload);
            if role == Some("user") {
                return if runtime_status == Some("completed") {
                    None
                } else {
                    runtime_status
                };
            }

            if role.is_some_and(is_terminal_reply_role) {
                return runtime_status.or(Some("completed"));
            }

            runtime_status
        }
        "message.deleted" | "message.edited" | "artifact.upserted" | "session.started" => {
            runtime_status
        }
        _ => runtime_status,
    }
}

fn is_terminal_reply_role(role: &str) -> bool {
    matches!(role, "assistant" | "planner" | "reviewer" | "tool")
}

fn sqlite_value_ref_to_string(value: ValueRef<'_>) -> Option<String> {
    match value {
        ValueRef::Null => None,
        ValueRef::Integer(integer) => Some(integer.to_string()),
        ValueRef::Real(real) => {
            if real.fract() == 0.0 {
                Some((real as i64).to_string())
            } else {
                Some(real.to_string())
            }
        }
        ValueRef::Text(text) => Some(String::from_utf8_lossy(text).into_owned()),
        ValueRef::Blob(_) => None,
    }
}

fn normalize_decimal_string_identifier(value: Option<&str>) -> Option<String> {
    let normalized = normalize_required_string(value?.to_owned())?;
    normalized
        .parse::<i64>()
        .ok()
        .filter(|candidate| *candidate >= 0)
        .map(|candidate| candidate.to_string())
}

fn normalize_organization_id_or_default(value: Option<String>) -> String {
    normalize_optional_string(value)
        .unwrap_or_else(|| SQLITE_AUTHORITY_DEFAULT_ORGANIZATION_ID.to_owned())
}

fn sqlite_row_required_string_value(
    row: &rusqlite::Row<'_>,
    index: usize,
    column_name: &str,
) -> rusqlite::Result<String> {
    let value = row.get_ref(index)?;
    let data_type = value.data_type();
    sqlite_value_ref_to_string(value).ok_or_else(|| {
        rusqlite::Error::FromSqlConversionFailure(
            index,
            data_type,
            Box::new(std::io::Error::new(
                std::io::ErrorKind::InvalidData,
                format!("sqlite column {column_name} could not be normalized as string"),
            )),
        )
    })
}

fn sqlite_row_optional_string_value(
    row: &rusqlite::Row<'_>,
    index: usize,
    column_name: &str,
) -> rusqlite::Result<Option<String>> {
    let value = row.get_ref(index)?;
    let data_type = value.data_type();
    match value {
        ValueRef::Null => Ok(None),
        _ => sqlite_value_ref_to_string(value).map(Some).ok_or_else(|| {
            rusqlite::Error::FromSqlConversionFailure(
                index,
                data_type,
                Box::new(std::io::Error::new(
                    std::io::ErrorKind::InvalidData,
                    format!(
                        "sqlite column {column_name} could not be normalized as optional string"
                    ),
                )),
            )
        }),
    }
}

fn sqlite_row_optional_data_scope_value(
    row: &rusqlite::Row<'_>,
    index: usize,
    column_name: &str,
) -> rusqlite::Result<Option<String>> {
    let value = row.get_ref(index)?;
    let data_type = value.data_type();
    let normalized_value = match value {
        ValueRef::Null => return Ok(None),
        ValueRef::Integer(value) => data_scope_name_from_storage_value(value).map(str::to_owned),
        ValueRef::Real(value) if value.fract() == 0.0 => {
            data_scope_name_from_storage_value(value as i64).map(str::to_owned)
        }
        ValueRef::Text(text) => normalize_data_scope(Some(
            String::from_utf8_lossy(text).into_owned(),
        ))
        .map_err(|message| {
            rusqlite::Error::FromSqlConversionFailure(
                index,
                data_type,
                Box::new(std::io::Error::new(
                    std::io::ErrorKind::InvalidData,
                    message,
                )),
            )
        })?,
        ValueRef::Blob(_) | ValueRef::Real(_) => None,
    };

    normalized_value
        .ok_or_else(|| {
            rusqlite::Error::FromSqlConversionFailure(
                index,
                data_type,
                Box::new(std::io::Error::new(
                    std::io::ErrorKind::InvalidData,
                    format!("sqlite column {column_name} could not be normalized as PlusDataScope"),
                )),
            )
        })
        .map(Some)
}

fn sqlite_row_optional_project_type_value(
    row: &rusqlite::Row<'_>,
    index: usize,
    column_name: &str,
) -> rusqlite::Result<Option<String>> {
    let value = row.get_ref(index)?;
    let data_type = value.data_type();
    match value {
        ValueRef::Null => Ok(None),
        ValueRef::Integer(value) => {
            Ok(project_type_name_from_storage_value(value).map(str::to_owned))
        }
        ValueRef::Real(value) if value.fract() == 0.0 => {
            Ok(project_type_name_from_storage_value(value as i64).map(str::to_owned))
        }
        ValueRef::Text(text) => {
            let raw = String::from_utf8_lossy(text).into_owned();
            let trimmed = raw.trim();
            if trimmed.is_empty() {
                Ok(None)
            } else {
                Ok(trimmed
                    .parse::<i64>()
                    .ok()
                    .and_then(project_type_name_from_storage_value)
                    .map(str::to_owned)
                    .or_else(|| Some(raw)))
            }
        }
        ValueRef::Blob(_) | ValueRef::Real(_) => Err(rusqlite::Error::FromSqlConversionFailure(
            index,
            data_type,
            Box::new(std::io::Error::new(
                std::io::ErrorKind::InvalidData,
                format!("sqlite column {column_name} could not be normalized as project type"),
            )),
        )),
    }
}

fn sqlite_row_required_project_status_value(
    row: &rusqlite::Row<'_>,
    index: usize,
    column_name: &str,
) -> rusqlite::Result<String> {
    let value = row.get_ref(index)?;
    let data_type = value.data_type();
    match value {
        ValueRef::Integer(value) => project_status_name_from_storage_value(value)
            .map(str::to_owned)
            .ok_or_else(|| {
                rusqlite::Error::FromSqlConversionFailure(
                    index,
                    data_type,
                    Box::new(std::io::Error::new(
                        std::io::ErrorKind::InvalidData,
                        format!("sqlite column {column_name} has unsupported project status"),
                    )),
                )
            }),
        ValueRef::Real(value) if value.fract() == 0.0 => {
            project_status_name_from_storage_value(value as i64)
                .map(str::to_owned)
                .ok_or_else(|| {
                    rusqlite::Error::FromSqlConversionFailure(
                        index,
                        data_type,
                        Box::new(std::io::Error::new(
                            std::io::ErrorKind::InvalidData,
                            format!("sqlite column {column_name} has unsupported project status"),
                        )),
                    )
                })
        }
        ValueRef::Text(text) => {
            let raw = String::from_utf8_lossy(text).into_owned();
            let trimmed = raw.trim();
            if let Ok(value) = trimmed.parse::<i64>() {
                Ok(project_status_name_from_storage_value(value)
                    .unwrap_or("PLANNING")
                    .to_owned())
            } else if trimmed.is_empty() {
                Ok("PLANNING".to_owned())
            } else {
                Ok(raw)
            }
        }
        ValueRef::Null | ValueRef::Blob(_) | ValueRef::Real(_) => {
            Err(rusqlite::Error::FromSqlConversionFailure(
                index,
                data_type,
                Box::new(std::io::Error::new(
                    std::io::ErrorKind::InvalidData,
                    format!(
                        "sqlite column {column_name} could not be normalized as project status"
                    ),
                )),
            ))
        }
    }
}

fn backfill_sqlite_timestamp_column(
    connection: &mut Connection,
    table_name: &str,
    column_name: &str,
) -> Result<(), String> {
    let select_statement =
        format!("SELECT rowid, {column_name} FROM {table_name} WHERE {column_name} IS NOT NULL");
    let mut statement = connection
        .prepare(&select_statement)
        .map_err(|error| {
            format!(
                "prepare sqlite timestamp normalization query for {table_name}.{column_name} failed: {error}"
            )
        })?;
    let mut rows = statement.query([]).map_err(|error| {
        format!(
            "query sqlite timestamp normalization rows for {table_name}.{column_name} failed: {error}"
        )
    })?;
    let mut pending_updates: Vec<(i64, String)> = Vec::new();

    while let Some(row) = rows.next().map_err(|error| {
        format!(
            "read sqlite timestamp normalization row for {table_name}.{column_name} failed: {error}"
        )
    })? {
        let row_id = row.get::<_, i64>(0).map_err(|error| {
            format!(
                "read sqlite timestamp normalization rowid for {table_name}.{column_name} failed: {error}"
            )
        })?;
        let Some(raw_value) = sqlite_value_ref_to_string(row.get_ref(1).map_err(|error| {
            format!(
                "read sqlite timestamp normalization value for {table_name}.{column_name} failed: {error}"
            )
        })?) else {
            continue;
        };
        let trimmed_value = raw_value.trim();
        let Some(normalized_value) = normalize_storage_timestamp_value(trimmed_value) else {
            continue;
        };

        if normalized_value != trimmed_value {
            pending_updates.push((row_id, normalized_value));
        }
    }

    drop(rows);
    drop(statement);

    if pending_updates.is_empty() {
        return Ok(());
    }

    let update_statement = format!("UPDATE {table_name} SET {column_name} = ?1 WHERE rowid = ?2");
    for (row_id, normalized_value) in pending_updates {
        connection
            .execute(&update_statement, params![normalized_value, row_id])
            .map_err(|error| {
                format!(
                    "update sqlite timestamp normalization for {table_name}.{column_name} rowid {row_id} failed: {error}"
                )
            })?;
    }

    Ok(())
}

fn ensure_sqlite_provider_authority_timestamp_normalization(
    connection: &mut Connection,
) -> Result<(), String> {
    let table_names = [
        PROVIDER_WORKSPACES_TABLE,
        PROVIDER_PROJECTS_TABLE,
        PROVIDER_CODING_SESSIONS_TABLE,
        PROVIDER_CODING_SESSION_RUNTIMES_TABLE,
        PROVIDER_CODING_SESSION_TURNS_TABLE,
        PROVIDER_CODING_SESSION_EVENTS_TABLE,
        PROVIDER_CODING_SESSION_ARTIFACTS_TABLE,
        PROVIDER_CODING_SESSION_CHECKPOINTS_TABLE,
        PROVIDER_CODING_SESSION_OPERATIONS_TABLE,
        PROVIDER_SKILL_PACKAGES_TABLE,
        PROVIDER_SKILL_VERSIONS_TABLE,
        PROVIDER_SKILL_CAPABILITIES_TABLE,
        PROVIDER_SKILL_INSTALLATIONS_TABLE,
        PROVIDER_APP_TEMPLATES_TABLE,
        PROVIDER_APP_TEMPLATE_VERSIONS_TABLE,
        PROVIDER_APP_TEMPLATE_TARGET_PROFILES_TABLE,
        PROVIDER_APP_TEMPLATE_PRESETS_TABLE,
        PROVIDER_APP_TEMPLATE_INSTANTIATIONS_TABLE,
        PROVIDER_PROJECT_DOCUMENTS_TABLE,
        PROVIDER_DEPLOYMENT_TARGETS_TABLE,
        PROVIDER_DEPLOYMENT_RECORDS_TABLE,
        PROVIDER_TEAMS_TABLE,
        PROVIDER_TEAM_MEMBERS_TABLE,
        PROVIDER_RELEASE_RECORDS_TABLE,
        PROVIDER_AUDIT_EVENTS_TABLE,
        PROVIDER_GOVERNANCE_POLICIES_TABLE,
    ];
    let timestamp_columns = [
        "created_at",
        "updated_at",
        "last_turn_at",
        "started_at",
        "completed_at",
        "start_time",
        "end_time",
    ];

    for table_name in table_names {
        if !sqlite_table_exists(connection, table_name)? {
            continue;
        }

        for column_name in timestamp_columns {
            if !sqlite_column_exists(connection, table_name, column_name)? {
                continue;
            }
            backfill_sqlite_timestamp_column(connection, table_name, column_name)?;
        }
    }

    Ok(())
}

fn backfill_team_business_columns(connection: &mut Connection) -> Result<(), String> {
    let team_rows = {
        let mut statement = connection
            .prepare(
                r#"
                SELECT
                    id,
                    workspace_id,
                    name,
                    tenant_id,
                    organization_id,
                    owner_id,
                    leader_id,
                    created_by_user_id,
                    uuid,
                    code,
                    title,
                    metadata_json
                FROM teams
                WHERE is_deleted = 0
                "#,
            )
            .map_err(|error| format!("prepare team canonical migration failed: {error}"))?;
        let mut rows = statement
            .query([])
            .map_err(|error| format!("query team canonical migration failed: {error}"))?;
        let mut records = Vec::new();
        while let Some(row) = rows
            .next()
            .map_err(|error| format!("read team canonical migration row failed: {error}"))?
        {
            records.push((
                sqlite_row_required_string_value(row, 0, "teams.id")
                    .map_err(|error| format!("read team canonical id failed: {error}"))?,
                sqlite_row_required_string_value(row, 1, "teams.workspace_id")
                    .map_err(|error| format!("read team canonical workspace_id failed: {error}"))?,
                row.get::<_, String>(2)
                    .map_err(|error| format!("read team canonical name failed: {error}"))?,
                sqlite_row_optional_string_value(row, 3, "teams.tenant_id")
                    .map_err(|error| format!("read team canonical tenant_id failed: {error}"))?,
                sqlite_row_optional_string_value(row, 4, "teams.organization_id").map_err(
                    |error| format!("read team canonical organization_id failed: {error}"),
                )?,
                sqlite_row_optional_string_value(row, 5, "teams.owner_id")
                    .map_err(|error| format!("read team canonical owner_id failed: {error}"))?,
                sqlite_row_optional_string_value(row, 6, "teams.leader_id")
                    .map_err(|error| format!("read team canonical leader_id failed: {error}"))?,
                sqlite_row_optional_string_value(row, 7, "teams.created_by_user_id").map_err(
                    |error| format!("read team canonical created_by_user_id failed: {error}"),
                )?,
                row.get::<_, Option<String>>(8)
                    .map_err(|error| format!("read team canonical uuid failed: {error}"))?,
                row.get::<_, Option<String>>(9)
                    .map_err(|error| format!("read team canonical code failed: {error}"))?,
                row.get::<_, Option<String>>(10)
                    .map_err(|error| format!("read team canonical title failed: {error}"))?,
                row.get::<_, Option<String>>(11).map_err(|error| {
                    format!("read team canonical metadata_json failed: {error}")
                })?,
            ));
        }
        records
    };

    for (
        team_id,
        workspace_id,
        team_name,
        tenant_id,
        organization_id,
        owner_id,
        leader_id,
        created_by_user_id,
        uuid,
        code,
        title,
        metadata_json,
    ) in team_rows
    {
        let workspace_scope = connection
            .query_row(
                r#"
                SELECT tenant_id, organization_id
                FROM plus_workspace AS workspaces
                WHERE id = ?1 AND is_deleted = 0
                LIMIT 1
                "#,
                params![&workspace_id],
                |row| {
                    Ok((
                        sqlite_row_optional_string_value(row, 0, "workspaces.tenant_id")?,
                        sqlite_row_optional_string_value(row, 1, "workspaces.organization_id")?,
                    ))
                },
            )
            .optional()
            .map_err(|error| format!("read team workspace scope {team_id} failed: {error}"))?
            .unwrap_or((None, None));
        let (resolved_owner_id, resolved_leader_id, resolved_created_by_user_id) =
            resolve_effective_user_authority(
                owner_id.as_deref(),
                leader_id.as_deref(),
                created_by_user_id.as_deref(),
                None,
                None,
                None,
            );
        let resolved_uuid =
            normalize_optional_string(uuid).unwrap_or_else(|| Uuid::new_v4().to_string());
        let resolved_tenant_id = normalize_optional_string(tenant_id)
            .or(workspace_scope.0)
            .unwrap_or_else(|| SQLITE_AUTHORITY_DEFAULT_TENANT_ID.to_owned());
        let resolved_organization_id = normalize_organization_id_or_default(
            normalize_optional_string(organization_id).or(workspace_scope.1),
        );
        let resolved_code = normalize_optional_string(code)
            .unwrap_or_else(|| build_team_business_code(&team_id, &team_name));
        let resolved_title = normalize_optional_string(title).unwrap_or_else(|| team_name.clone());
        let resolved_metadata_json =
            normalize_optional_string(metadata_json).unwrap_or_else(|| "{}".to_owned());

        connection
            .execute(
                r#"
                UPDATE teams
                SET
                    uuid = ?2,
                    tenant_id = ?3,
                    organization_id = ?4,
                    code = ?5,
                    title = ?6,
                    owner_id = ?7,
                    leader_id = ?8,
                    created_by_user_id = ?9,
                    metadata_json = ?10
                WHERE id = ?1
                "#,
                params![
                    &team_id,
                    &resolved_uuid,
                    &resolved_tenant_id,
                    &resolved_organization_id,
                    &resolved_code,
                    &resolved_title,
                    &resolved_owner_id,
                    &resolved_leader_id,
                    &resolved_created_by_user_id,
                    &resolved_metadata_json,
                ],
            )
            .map_err(|error| format!("backfill team canonical fields {team_id} failed: {error}"))?;
    }

    Ok(())
}

