    fn create_coding_session_turn(
        &self,
        coding_session_id: &str,
        input: CreateCodingSessionTurnInput,
        working_directory: Option<&FsPath>,
    ) -> Result<PendingProjectionTurnExecution, String> {
        let snapshot = self
            .session_snapshot(coding_session_id)
            .ok_or_else(|| format!("coding session {coding_session_id} was not found"))?;
        let session = snapshot
            .session
            .clone()
            .ok_or_else(|| format!("coding session {coding_session_id} has no session payload"))?;
        resolve_authoritative_engine_runtime_profile(
            session.engine_id.as_str(),
            session.host_mode.as_str(),
        )
        .map_err(|error| {
            format!("coding session {coding_session_id} cannot execute turns: {error}")
        })?;
        let started_at = current_session_timestamp();
        let provider_runtime_row = if let Some(sqlite_file) = self.sqlite_file.as_deref() {
            let mut connection = Connection::open(sqlite_file).map_err(|error| {
                format!(
                    "open sqlite coding-session turn authority {} failed: {error}",
                    sqlite_file.display()
                )
            })?;
            ensure_sqlite_provider_authority(&mut connection, sqlite_file)?;
            load_provider_runtime_row_for_session(
                &connection,
                coding_session_id,
                input.runtime_id.as_deref(),
            )?
        } else {
            None
        };
        let runtime_id = provider_runtime_row
            .as_ref()
            .map(|runtime| runtime.id.clone())
            .or(input.runtime_id.clone())
            .unwrap_or_else(|| derive_runtime_id(&snapshot, coding_session_id));
        let native_session_id = provider_runtime_row
            .as_ref()
            .and_then(|runtime| runtime.native_session_id.clone())
            .or_else(|| resolve_native_session_id_from_snapshot(&snapshot));
        let turn_id = create_identifier("coding-turn");
        let operation_id = format!("{turn_id}:operation");
        let request_kind = input.request_kind;
        let input_summary = input.input_summary;
        let base_sequence = next_event_sequence(&snapshot);
        let turn = CodingSessionTurnPayload {
            id: turn_id.clone(),
            coding_session_id: coding_session_id.to_owned(),
            runtime_id: Some(runtime_id.clone()),
            request_kind: request_kind.clone(),
            status: "running".to_owned(),
            input_summary: input_summary.clone(),
            started_at: Some(started_at.clone()),
            completed_at: None,
        };
        let operation = OperationPayload {
            operation_id: operation_id.clone(),
            status: "running".to_owned(),
            artifact_refs: Vec::new(),
            stream_url: format!("/api/core/v1/coding-sessions/{coding_session_id}/events"),
            stream_kind: "sse".to_owned(),
        };
        let events = build_initialized_coding_session_turn_events(
            &session,
            coding_session_id,
            runtime_id.as_str(),
            turn_id.as_str(),
            request_kind.as_str(),
            input_summary.as_str(),
            operation_id.as_str(),
            base_sequence,
            started_at.as_str(),
            native_session_id.as_deref(),
        );

        if let Some(sqlite_file) = self.sqlite_file.as_deref() {
            let mut connection = Connection::open(sqlite_file).map_err(|error| {
                format!(
                    "open sqlite coding-session turn authority {} failed: {error}",
                    sqlite_file.display()
                )
            })?;
            ensure_sqlite_provider_authority(&mut connection, sqlite_file)?;
            persist_initialized_coding_session_turn_to_provider(
                &mut connection,
                &turn,
                &events,
                &operation,
                native_session_id.as_deref(),
            )?;
            let reloaded_state = ProjectionReadState::from_sqlite_provider_connection(&connection)?;
            *self
                .state
                .write()
                .expect("write projection authority state") = reloaded_state;
        } else {
            let mut state = self
                .state
                .write()
                .expect("write projection authority state");
            let snapshot = state
                .sessions
                .get_mut(coding_session_id)
                .ok_or_else(|| format!("coding session {coding_session_id} was not found"))?;
            if let Some(session) = snapshot.session.as_mut() {
                session.updated_at = started_at.clone();
                session.last_turn_at = Some(started_at.clone());
            }
            snapshot.turns.push(turn.clone());
            snapshot.events.extend(events);
            snapshot.operations.push(operation.clone());
        }

        Ok(PendingProjectionTurnExecution {
            session,
            turn,
            operation,
            native_session_id,
            ide_context: input.ide_context,
            options: input.options,
            working_directory: working_directory.map(FsPath::to_path_buf),
        })
    }

    fn append_coding_session_stream_event(
        &self,
        pending: &PendingProjectionTurnExecution,
        kind: &str,
        role: &str,
        content_delta: &str,
        payload: Option<&serde_json::Value>,
        native_session_id: Option<&str>,
    ) -> Result<Option<CodingSessionEventPayload>, String> {
        let normalized_kind = kind.trim();
        let normalized_role = role.trim();
        let normalized_content_delta = content_delta;
        if normalized_kind.is_empty() || normalized_role.is_empty() {
            return Ok(None);
        }
        if normalized_kind == "message.delta" && normalized_content_delta.is_empty() {
            return Ok(None);
        }
        if normalized_kind != "message.delta"
            && normalized_content_delta.is_empty()
            && payload
                .and_then(serde_json::Value::as_object)
                .map(serde_json::Map::is_empty)
                .unwrap_or(true)
        {
            return Ok(None);
        }

        let coding_session_id = pending.turn.coding_session_id.as_str();
        let runtime_id = pending
            .turn
            .runtime_id
            .as_deref()
            .ok_or("coding session turn runtimeId is required.")?;
        let created_at = current_session_timestamp();

        if let Some(sqlite_file) = self.sqlite_file.as_deref() {
            let mut connection = Connection::open(sqlite_file).map_err(|error| {
                format!(
                    "open sqlite coding-session streaming authority {} failed: {error}",
                    sqlite_file.display()
                )
            })?;
            ensure_sqlite_provider_authority(&mut connection, sqlite_file)?;
            let provider_state = ProjectionReadState::from_sqlite_provider_connection(&connection)?;
            let snapshot = provider_state
                .session_snapshot(coding_session_id)
                .ok_or_else(|| format!("coding session {coding_session_id} was not found"))?;
            let event = build_streaming_coding_session_event(
                coding_session_id,
                runtime_id,
                pending.turn.id.as_str(),
                pending.operation.operation_id.as_str(),
                normalized_kind,
                normalized_role,
                normalized_content_delta,
                payload,
                next_event_sequence(&snapshot),
                created_at.as_str(),
                native_session_id,
            );
            persist_streaming_coding_session_event_to_provider(
                &mut connection,
                &event,
                native_session_id,
            )?;
            let reloaded_state = ProjectionReadState::from_sqlite_provider_connection(&connection)?;
            *self
                .state
                .write()
                .expect("write projection authority state") = reloaded_state;
            return Ok(Some(event));
        }

        let mut state = self
            .state
            .write()
            .expect("write projection authority state");
        let snapshot = state
            .sessions
            .get_mut(coding_session_id)
            .ok_or_else(|| format!("coding session {coding_session_id} was not found"))?;
        let event = build_streaming_coding_session_event(
            coding_session_id,
            runtime_id,
            pending.turn.id.as_str(),
            pending.operation.operation_id.as_str(),
            normalized_kind,
            normalized_role,
            normalized_content_delta,
            payload,
            next_event_sequence(snapshot),
            created_at.as_str(),
            native_session_id,
        );
        if let Some(session) = snapshot.session.as_mut() {
            session.updated_at = created_at.clone();
            session.last_turn_at = Some(created_at.clone());
        }
        snapshot.events.push(event);

        Ok(snapshot.events.last().cloned())
    }

    fn complete_coding_session_turn(
        &self,
        pending: &PendingProjectionTurnExecution,
        assistant_content: &str,
        commands: Option<&[native_sessions::NativeSessionCommandPayload]>,
        resolved_native_session_id: Option<&str>,
    ) -> Result<FinalizedProjectionTurnExecution, String> {
        let completed_at = current_session_timestamp();
        let mut completed_turn = pending.turn.clone();
        completed_turn.status = "completed".to_owned();
        completed_turn.completed_at = Some(completed_at.clone());

        let mut completed_operation = pending.operation.clone();
        completed_operation.status = "succeeded".to_owned();

        let snapshot = self
            .session_snapshot(completed_turn.coding_session_id.as_str())
            .ok_or_else(|| {
                format!(
                    "coding session {} was not found while completing turn {}",
                    completed_turn.coding_session_id, completed_turn.id
                )
            })?;
        let runtime_id = completed_turn
            .runtime_id
            .as_deref()
            .ok_or("coding session turn runtimeId is required.")?;
        let completion_events = build_succeeded_coding_session_turn_events(
            completed_turn.coding_session_id.as_str(),
            runtime_id,
            completed_turn.id.as_str(),
            completed_operation.operation_id.as_str(),
            assistant_content,
            commands,
            next_event_sequence(&snapshot),
            completed_at.as_str(),
            resolved_native_session_id,
        );

        if let Some(sqlite_file) = self.sqlite_file.as_deref() {
            let mut connection = Connection::open(sqlite_file).map_err(|error| {
                format!(
                    "open sqlite coding-session completion authority {} failed: {error}",
                    sqlite_file.display()
                )
            })?;
            ensure_sqlite_provider_authority(&mut connection, sqlite_file)?;
            persist_finalized_coding_session_turn_to_provider(
                &mut connection,
                &completed_turn,
                &completion_events,
                &completed_operation,
                "completed",
                resolved_native_session_id,
            )?;
            let reloaded_state = ProjectionReadState::from_sqlite_provider_connection(&connection)?;
            *self
                .state
                .write()
                .expect("write projection authority state") = reloaded_state;
            return Ok(FinalizedProjectionTurnExecution {
                turn: completed_turn,
                events: completion_events,
            });
        }

        let mut state = self
            .state
            .write()
            .expect("write projection authority state");
        let snapshot = state
            .sessions
            .get_mut(completed_turn.coding_session_id.as_str())
            .ok_or_else(|| {
                format!(
                    "coding session {} was not found while completing turn {}",
                    completed_turn.coding_session_id, completed_turn.id
                )
            })?;
        if let Some(session) = snapshot.session.as_mut() {
            session.updated_at = completed_at.clone();
            session.last_turn_at = Some(completed_at.clone());
        }
        if let Some(turn) = snapshot
            .turns
            .iter_mut()
            .find(|turn| turn.id == completed_turn.id)
        {
            *turn = completed_turn.clone();
        }
        if let Some(operation) = snapshot
            .operations
            .iter_mut()
            .find(|operation| operation.operation_id == completed_operation.operation_id)
        {
            *operation = completed_operation;
        }
        snapshot.events.extend(completion_events.clone());

        Ok(FinalizedProjectionTurnExecution {
            turn: completed_turn,
            events: completion_events,
        })
    }

    fn fail_coding_session_turn(
        &self,
        pending: &PendingProjectionTurnExecution,
        error_message: &str,
        resolved_native_session_id: Option<&str>,
    ) -> Result<FinalizedProjectionTurnExecution, String> {
        let completed_at = current_session_timestamp();
        let mut failed_turn = pending.turn.clone();
        failed_turn.status = "failed".to_owned();
        failed_turn.completed_at = Some(completed_at.clone());

        let mut failed_operation = pending.operation.clone();
        failed_operation.status = "failed".to_owned();

        let snapshot = self
            .session_snapshot(failed_turn.coding_session_id.as_str())
            .ok_or_else(|| {
                format!(
                    "coding session {} was not found while failing turn {}",
                    failed_turn.coding_session_id, failed_turn.id
                )
            })?;
        let runtime_id = failed_turn
            .runtime_id
            .as_deref()
            .ok_or("coding session turn runtimeId is required.")?;
        let include_terminal_failure_event =
            !projection_turn_has_event_kind(&snapshot, failed_turn.id.as_str(), "turn.failed");
        let failure_events = build_failed_coding_session_turn_events(
            failed_turn.coding_session_id.as_str(),
            runtime_id,
            failed_turn.id.as_str(),
            failed_operation.operation_id.as_str(),
            error_message,
            next_event_sequence(&snapshot),
            completed_at.as_str(),
            resolved_native_session_id,
            include_terminal_failure_event,
        );

        if let Some(sqlite_file) = self.sqlite_file.as_deref() {
            let mut connection = Connection::open(sqlite_file).map_err(|error| {
                format!(
                    "open sqlite coding-session failure authority {} failed: {error}",
                    sqlite_file.display()
                )
            })?;
            ensure_sqlite_provider_authority(&mut connection, sqlite_file)?;
            persist_finalized_coding_session_turn_to_provider(
                &mut connection,
                &failed_turn,
                &failure_events,
                &failed_operation,
                "failed",
                resolved_native_session_id,
            )?;
            let reloaded_state = ProjectionReadState::from_sqlite_provider_connection(&connection)?;
            *self
                .state
                .write()
                .expect("write projection authority state") = reloaded_state;
            return Ok(FinalizedProjectionTurnExecution {
                turn: failed_turn,
                events: failure_events,
            });
        }

        let mut state = self
            .state
            .write()
            .expect("write projection authority state");
        let snapshot = state
            .sessions
            .get_mut(failed_turn.coding_session_id.as_str())
            .ok_or_else(|| {
                format!(
                    "coding session {} was not found while failing turn {}",
                    failed_turn.coding_session_id, failed_turn.id
                )
            })?;
        if let Some(session) = snapshot.session.as_mut() {
            session.updated_at = completed_at.clone();
            session.last_turn_at = Some(completed_at.clone());
        }
        if let Some(turn) = snapshot
            .turns
            .iter_mut()
            .find(|turn| turn.id == failed_turn.id)
        {
            *turn = failed_turn.clone();
        }
        if let Some(operation) = snapshot
            .operations
            .iter_mut()
            .find(|operation| operation.operation_id == failed_operation.operation_id)
        {
            *operation = failed_operation;
        }
        snapshot.events.extend(failure_events.clone());

        Ok(FinalizedProjectionTurnExecution {
            turn: failed_turn,
            events: failure_events,
        })
    }

    fn submit_approval_decision(
        &self,
        approval_id: &str,
        input: SubmitApprovalDecisionInput,
    ) -> Result<ProjectionMutationEvent<ApprovalDecisionPayload>, String> {
        let decided_at = current_session_timestamp();

        if let Some(sqlite_file) = self.sqlite_file.as_deref() {
            let mut connection = Connection::open(sqlite_file).map_err(|error| {
                format!(
                    "open sqlite approval authority {} failed: {error}",
                    sqlite_file.display()
                )
            })?;
            ensure_sqlite_provider_authority(&mut connection, sqlite_file)?;
            let reloaded_state = ProjectionReadState::from_sqlite_provider_connection(&connection)?;
            let (coding_session_id, context) = reloaded_state
                .approval_context(approval_id)
                .ok_or_else(|| format!("approval {approval_id} was not found"))?;
            let decision = persist_approval_decision_to_provider(
                &mut connection,
                &reloaded_state,
                &coding_session_id,
                &context,
                approval_id,
                &input,
                &decided_at,
            )?;
            let refreshed_state =
                ProjectionReadState::from_sqlite_provider_connection(&connection)?;
            *self
                .state
                .write()
                .expect("write projection authority state") = refreshed_state;
            return Ok(decision);
        }

        let mut state = self
            .state
            .write()
            .expect("write projection authority state");
        let (coding_session_id, context) = state
            .approval_context(approval_id)
            .ok_or_else(|| format!("approval {approval_id} was not found"))?;
        let snapshot = state
            .sessions
            .get_mut(&coding_session_id)
            .ok_or_else(|| format!("coding session {coding_session_id} was not found"))?;
        apply_approval_decision_to_snapshot(snapshot, &context, approval_id, &input, &decided_at)
    }

