#[derive(Serialize)]
#[serde(rename_all = "camelCase", tag = "kind")]
enum WorkspaceRealtimeMessagePayload {
    Ready {
        connected_at: String,
        user_id: String,
        workspace_id: String,
    },
    Event {
        event: WorkspaceRealtimeEventPayload,
    },
}

#[derive(Clone)]
struct WorkspaceRealtimeHub {
    sender: broadcast::Sender<WorkspaceRealtimeEventPayload>,
}

impl WorkspaceRealtimeHub {
    fn new() -> Self {
        let (sender, _) = broadcast::channel(256);
        Self { sender }
    }

    fn publish(&self, event: WorkspaceRealtimeEventPayload) {
        let _ = self.sender.send(event);
    }

    fn subscribe(&self) -> broadcast::Receiver<WorkspaceRealtimeEventPayload> {
        self.sender.subscribe()
    }
}

fn try_resolve_current_user_center_session(
    state: &AppState,
    headers: &HeaderMap,
) -> Option<UserCenterSessionPayload> {
    let connection = state.open_authority_connection_for_write().ok()?;
    state
        .user_center
        .resolve_session(&connection, headers)
        .ok()
        .flatten()
}

fn resolve_current_user_center_session(
    state: &AppState,
    headers: &HeaderMap,
    unavailable_seed: &str,
    unauthorized_seed: &str,
) -> Result<
    (Connection, UserCenterSessionPayload),
    (StatusCode, Json<ApiEnvelope<ProblemDetailsPayload>>),
> {
    let connection = state
        .open_authority_connection_for_write()
        .map_err(|error| {
            problem_response(
                unavailable_seed,
                StatusCode::NOT_IMPLEMENTED,
                "system_error",
                error,
            )
        })?;
    let session = state
        .user_center
        .resolve_session(&connection, headers)
        .map_err(|error| {
            problem_response(
                unavailable_seed,
                StatusCode::INTERNAL_SERVER_ERROR,
                "system_error",
                error,
            )
        })?
        .ok_or_else(|| {
            problem_response(
                unauthorized_seed,
                StatusCode::UNAUTHORIZED,
                "unauthorized",
                "A valid user center session is required.",
            )
        })?;
    Ok((connection, session))
}

fn resolve_headers_with_optional_session_query(
    headers: &HeaderMap,
    query_session_id: Option<&str>,
) -> Result<HeaderMap, String> {
    let mut resolved_headers = headers.clone();
    if resolved_headers.contains_key(BIRDCODER_SESSION_HEADER_NAME) {
        return Ok(resolved_headers);
    }

    let Some(session_id) =
        query_session_id.and_then(|value| normalize_required_string(value.to_owned()))
    else {
        return Ok(resolved_headers);
    };
    let session_header_value = HeaderValue::from_str(session_id.as_str())
        .map_err(|error| format!("Invalid realtime sessionId query parameter: {error}"))?;
    resolved_headers.insert(
        HeaderName::from_static(BIRDCODER_SESSION_HEADER_NAME),
        session_header_value,
    );
    Ok(resolved_headers)
}

fn resolve_request_base_url(headers: &HeaderMap) -> Option<String> {
    if let Some(origin) = headers
        .get(header::ORIGIN)
        .and_then(|value| value.to_str().ok())
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        return Some(origin.to_owned());
    }

    let host = headers
        .get(header::HOST)
        .and_then(|value| value.to_str().ok())
        .map(str::trim)
        .filter(|value| !value.is_empty())?;
    let scheme = headers
        .get("x-forwarded-proto")
        .and_then(|value| value.to_str().ok())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("http");

    Some(format!("{scheme}://{host}"))
}

fn render_user_center_qr_entry_html(qr_key: &str) -> String {
    let qr_key_json = serde_json::to_string(qr_key).unwrap_or_else(|_| "\"\"".to_owned());
    let confirm_path_json = serde_json::to_string(USER_CENTER_AUTH_QR_CONFIRM_PATH)
        .unwrap_or_else(|_| "\"\"".to_owned());
    let session_header_name_json =
        serde_json::to_string(BIRDCODER_SESSION_HEADER_NAME).unwrap_or_else(|_| "\"\"".to_owned());
    let session_storage_key_json =
        serde_json::to_string(BIRDCODER_USER_CENTER_SESSION_TOKEN_STORAGE_KEY)
            .unwrap_or_else(|_| "\"\"".to_owned());

    format!(
        r#"<!DOCTYPE html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width,initial-scale=1" />
    <title>BirdCoder QR Sign In</title>
    <style>
      :root {{
        color-scheme: dark;
        font-family: "Segoe UI", system-ui, sans-serif;
      }}
      body {{
        margin: 0;
        min-height: 100vh;
        display: flex;
        align-items: center;
        justify-content: center;
        background:
          radial-gradient(circle at top, rgba(74, 144, 226, 0.18), transparent 42%),
          linear-gradient(180deg, #09090b 0%, #0f172a 100%);
        color: #f4f4f5;
      }}
      .card {{
        width: min(460px, calc(100vw - 32px));
        border-radius: 28px;
        padding: 28px;
        background: rgba(12, 18, 28, 0.9);
        border: 1px solid rgba(255, 255, 255, 0.08);
        box-shadow: 0 32px 80px rgba(0, 0, 0, 0.45);
      }}
      .eyebrow {{
        display: inline-flex;
        align-items: center;
        gap: 8px;
        padding: 8px 12px;
        border-radius: 999px;
        background: rgba(255, 255, 255, 0.08);
        font-size: 12px;
        letter-spacing: 0.16em;
        text-transform: uppercase;
      }}
      h1 {{
        margin: 18px 0 10px;
        font-size: 30px;
        line-height: 1.15;
      }}
      p {{
        margin: 0;
        color: rgba(228, 228, 231, 0.78);
        line-height: 1.7;
      }}
      .panel {{
        margin-top: 24px;
        padding: 18px;
        border-radius: 22px;
        background: rgba(255, 255, 255, 0.05);
        border: 1px solid rgba(255, 255, 255, 0.08);
      }}
      .status {{
        color: #bfdbfe;
        font-weight: 700;
        margin-bottom: 8px;
      }}
      .meta {{
        margin-top: 14px;
        font-size: 12px;
        color: rgba(161, 161, 170, 0.88);
        word-break: break-all;
      }}
      button {{
        margin-top: 22px;
        width: 100%;
        height: 48px;
        border: 0;
        border-radius: 16px;
        background: linear-gradient(135deg, #2563eb, #1d4ed8);
        color: white;
        font-size: 15px;
        font-weight: 700;
        cursor: pointer;
      }}
      button:disabled {{
        opacity: 0.55;
        cursor: wait;
      }}
    </style>
  </head>
  <body>
    <main class="card">
      <div class="eyebrow">BirdCoder QR Session</div>
      <h1>Confirm Sign In</h1>
      <p>Open this page on a device that is already signed in to BirdCoder, then confirm to transfer that session back to the original login screen.</p>
      <section class="panel">
        <div id="status" class="status">Waiting for confirmation</div>
        <p id="message">If this device is already signed in, confirmation will run automatically. Otherwise sign in first and retry.</p>
        <div class="meta">QR Key: <span id="qr-key"></span></div>
      </section>
      <button id="confirm-button" type="button">Confirm Sign In</button>
    </main>
    <script>
      const qrKey = {qr_key_json};
      const confirmPath = {confirm_path_json};
      const sessionHeaderName = {session_header_name_json};
      const sessionStorageKey = {session_storage_key_json};
      const statusElement = document.getElementById("status");
      const messageElement = document.getElementById("message");
      const confirmButton = document.getElementById("confirm-button");
      const qrKeyElement = document.getElementById("qr-key");
      qrKeyElement.textContent = qrKey;

      function readSessionToken() {{
        const stores = [window.localStorage, window.sessionStorage];
        for (const store of stores) {{
          try {{
            const value = store.getItem(sessionStorageKey);
            if (value && value.trim()) {{
              return value.trim();
            }}
          }} catch (_error) {{
          }}
        }}
        return "";
      }}

      async function confirmLogin() {{
        const sessionToken = readSessionToken();
        if (!sessionToken) {{
          statusElement.textContent = "Sign in required";
          messageElement.textContent = "No BirdCoder session token was found on this device. Sign in to BirdCoder here first, then retry confirmation.";
          return;
        }}

        confirmButton.disabled = true;
        statusElement.textContent = "Confirming sign in";
        messageElement.textContent = "Syncing this signed-in BirdCoder session back to the original device.";

        try {{
          const response = await fetch(confirmPath, {{
            method: "POST",
            headers: {{
              "Content-Type": "application/json",
              [sessionHeaderName]: sessionToken,
            }},
            body: JSON.stringify({{ qrKey }}),
          }});
          const payload = await response.json().catch(() => null);

          if (!response.ok) {{
            const nextMessage =
              payload?.data?.message
              || payload?.message
              || "BirdCoder could not confirm this QR session.";
            throw new Error(nextMessage);
          }}

          statusElement.textContent = "Sign in confirmed";
          messageElement.textContent = "The original BirdCoder login screen can finish sign-in now. You can close this page.";
          confirmButton.style.display = "none";
        }} catch (error) {{
          statusElement.textContent = "Confirmation failed";
          messageElement.textContent =
            error instanceof Error ? error.message : "BirdCoder could not confirm this QR session.";
          confirmButton.disabled = false;
        }}
      }}

      confirmButton.addEventListener("click", () => {{
        void confirmLogin();
      }});

      if (readSessionToken()) {{
        void confirmLogin();
      }}
    </script>
  </body>
</html>"#
    )
}

async fn send_workspace_realtime_message(
    socket: &mut WebSocket,
    payload: &WorkspaceRealtimeMessagePayload,
) -> Result<(), String> {
    let serialized_payload = serde_json::to_string(payload)
        .map_err(|error| format!("Serialize realtime payload failed: {error}"))?;
    socket
        .send(Message::Text(serialized_payload.into()))
        .await
        .map_err(|error| format!("Send realtime payload failed: {error}"))
}

async fn serve_workspace_realtime_socket(
    mut socket: WebSocket,
    hub: WorkspaceRealtimeHub,
    workspace_id: String,
    user_id: String,
) {
    let ready_message = WorkspaceRealtimeMessagePayload::Ready {
        connected_at: current_storage_timestamp(),
        user_id,
        workspace_id: workspace_id.clone(),
    };
    if send_workspace_realtime_message(&mut socket, &ready_message)
        .await
        .is_err()
    {
        return;
    }

    let mut receiver = hub.subscribe();
    loop {
        tokio::select! {
            next_event = receiver.recv() => {
                match next_event {
                    Ok(event) => {
                        if event.workspace_id != workspace_id {
                            continue;
                        }

                        let event_message = WorkspaceRealtimeMessagePayload::Event {
                            event,
                        };
                        if send_workspace_realtime_message(&mut socket, &event_message)
                            .await
                            .is_err()
                        {
                            break;
                        }
                    }
                    Err(broadcast::error::RecvError::Lagged(_)) => {
                        continue;
                    }
                    Err(broadcast::error::RecvError::Closed) => {
                        break;
                    }
                }
            }
            next_message = socket.recv() => {
                match next_message {
                    Some(Ok(Message::Ping(payload))) => {
                        if socket.send(Message::Pong(payload)).await.is_err() {
                            break;
                        }
                    }
                    Some(Ok(Message::Close(_))) | None => {
                        break;
                    }
                    Some(Ok(_)) => {}
                    Some(Err(_)) => {
                        break;
                    }
                }
            }
        }
    }
}

async fn app_workspace_realtime(
    ws: WebSocketUpgrade,
    AxumPath(workspace_id): AxumPath<String>,
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<WorkspaceRealtimeQueryParams>,
) -> Result<Response, (StatusCode, Json<ApiEnvelope<ProblemDetailsPayload>>)> {
    let normalized_workspace_id = normalize_required_string(workspace_id).ok_or_else(|| {
        problem_response(
            "workspace-realtime-invalid",
            StatusCode::BAD_REQUEST,
            "argument_invalid",
            "workspaceId is required.",
        )
    })?;
    if !state.has_workspace(normalized_workspace_id.as_str()) {
        return Err(problem_response(
            "workspace-realtime-workspace-not-found",
            StatusCode::NOT_FOUND,
            "not_found",
            "Workspace authority was not found.",
        ));
    }

    let resolved_headers =
        resolve_headers_with_optional_session_query(&headers, query.session_id.as_deref())
            .map_err(|error| {
                problem_response(
                    "workspace-realtime-session-invalid",
                    StatusCode::BAD_REQUEST,
                    "argument_invalid",
                    error,
                )
            })?;
    let (_, session) = resolve_current_user_center_session(
        &state,
        &resolved_headers,
        "workspace-realtime-auth-unavailable",
        "workspace-realtime-unauthorized",
    )?;

    let realtime_hub = state.realtime.clone();
    let current_user_id = session.user.id;
    Ok(ws.on_upgrade(move |socket| async move {
        serve_workspace_realtime_socket(
            socket,
            realtime_hub,
            normalized_workspace_id,
            current_user_id,
        )
        .await;
    }))
}

