fn problem_response(
    seed: &str,
    status: StatusCode,
    code: &'static str,
    message: impl Into<String>,
) -> (StatusCode, Json<ApiEnvelope<ProblemDetailsPayload>>) {
    (
        status,
        Json(create_envelope(
            seed,
            ProblemDetailsPayload {
                code,
                message: message.into(),
                retryable: false,
            },
        )),
    )
}

fn insert_optional_response_header(
    headers: &mut HeaderMap,
    header_name: HeaderName,
    value: Option<&str>,
) {
    let Some(normalized_value) = value.map(str::trim).filter(|entry| !entry.is_empty()) else {
        return;
    };
    let Ok(header_value) = HeaderValue::from_str(normalized_value) else {
        return;
    };
    headers.insert(header_name, header_value);
}

fn create_user_center_session_response_headers(
    session: Option<&UserCenterSessionPayload>,
) -> HeaderMap {
    let mut headers = HeaderMap::new();
    let Some(session) = session else {
        return headers;
    };

    insert_optional_response_header(
        &mut headers,
        HeaderName::from_static(BIRDCODER_SESSION_HEADER_NAME),
        Some(session.session_id.as_str()),
    );
    insert_optional_response_header(
        &mut headers,
        HeaderName::from_static("access-token"),
        Some(session.access_token.as_str()),
    );
    insert_optional_response_header(
        &mut headers,
        HeaderName::from_static("refresh-token"),
        session.refresh_token.as_deref(),
    );

    let authorization_scheme = session.token_type.trim();
    let authorization_token = session.auth_token.trim();
    if !authorization_token.is_empty() {
        let normalized_scheme = if authorization_scheme.is_empty() {
            BIRDCODER_AUTHORIZATION_SCHEME
        } else {
            authorization_scheme
        };
        let authorization_value = format!("{normalized_scheme} {authorization_token}");
        insert_optional_response_header(
            &mut headers,
            header::AUTHORIZATION,
            Some(authorization_value.as_str()),
        );
    }

    headers
}

fn projection_authority_error_status(error: &str) -> (StatusCode, &'static str) {
    if error.contains("is immutable after creation")
        || error.contains("is not executable by the Rust authority")
        || error.contains("cannot execute turns:")
        || error.contains("does not expose a ready transport")
        || error.contains("is not supported for engine")
    {
        return (StatusCode::BAD_REQUEST, "argument_invalid");
    }

    (StatusCode::INTERNAL_SERVER_ERROR, "system_error")
}

async fn core_operation(
    State(state): State<AppState>,
    AxumPath(operation_id): AxumPath<String>,
) -> Result<
    Json<ApiEnvelope<OperationPayload>>,
    (StatusCode, Json<ApiEnvelope<ProblemDetailsPayload>>),
> {
    let operation = state.projections.operation(&operation_id).ok_or_else(|| {
        problem_response(
            "operation-not-found",
            StatusCode::NOT_FOUND,
            "not_found",
            "Operation projection was not found.",
        )
    })?;

    Ok(Json(create_envelope("core-operation", operation)))
}

fn is_native_coding_session_id(coding_session_id: &str) -> bool {
    native_sessions::is_authority_backed_native_session_id(coding_session_id)
}

fn normalize_attached_native_session_id(
    engine_id: &str,
    native_session_id: &str,
) -> Option<String> {
    let normalized_native_session_id = native_session_id.trim();
    if normalized_native_session_id.is_empty() {
        return None;
    }

    Some(native_sessions::build_native_session_id(
        engine_id,
        normalized_native_session_id,
    ))
}

fn resolve_projection_attached_native_session_id(
    state: &AppState,
    coding_session_id: &str,
    engine_id: &str,
    snapshot: &ProjectionSnapshot,
) -> Option<String> {
    let latest_runtime_row = state
        .projections
        .sqlite_file
        .as_deref()
        .and_then(|sqlite_file| Connection::open(sqlite_file).ok())
        .and_then(|connection| {
            load_provider_runtime_row_for_session(&connection, coding_session_id, None)
                .ok()
                .flatten()
        });
    resolve_projection_attached_native_session_id_with_runtime_row(
        engine_id,
        snapshot,
        latest_runtime_row.as_ref(),
    )
}

fn resolve_projection_attached_native_session_id_with_runtime_row(
    engine_id: &str,
    snapshot: &ProjectionSnapshot,
    runtime_row: Option<&CodingSessionRuntimeRow>,
) -> Option<String> {
    let resolved_engine_id = runtime_row
        .and_then(|runtime| {
            let normalized_runtime_engine_id = runtime.engine_id.trim();
            (!normalized_runtime_engine_id.is_empty()).then_some(normalized_runtime_engine_id)
        })
        .unwrap_or(engine_id);
    let event_native_session_id =
        resolve_native_session_id_from_snapshot(snapshot).and_then(|native_session_id| {
            normalize_attached_native_session_id(resolved_engine_id, native_session_id.as_str())
        });
    if event_native_session_id.is_some() {
        return event_native_session_id;
    }

    runtime_row.and_then(|runtime| {
        runtime
            .native_session_id
            .as_ref()
            .and_then(|native_session_id| {
                normalize_attached_native_session_id(resolved_engine_id, native_session_id.as_str())
            })
    })
}

