async fn core_create_turn(
    State(state): State<AppState>,
    AxumPath(coding_session_id): AxumPath<String>,
    Query(query): Query<NativeSessionLookupQueryParams>,
    Json(request): Json<CreateCodingSessionTurnRequest>,
) -> Result<
    (StatusCode, Json<ApiEnvelope<CodingSessionTurnPayload>>),
    (StatusCode, Json<ApiEnvelope<ProblemDetailsPayload>>),
> {
    let input = CreateCodingSessionTurnInput::try_from(request).map_err(|message| {
        problem_response(
            "create-coding-session-turn-invalid",
            StatusCode::BAD_REQUEST,
            "argument_invalid",
            message,
        )
    })?;

    let native_engine_id = normalize_optional_string(query.engine_id);
    if state.projections.session(&coding_session_id).is_none()
        && (is_native_coding_session_id(&coding_session_id) || native_engine_id.is_some())
    {
        let turn = create_native_coding_session_turn(
            &state,
            &coding_session_id,
            native_engine_id.clone(),
            &input,
        )
        .map_err(|error| {
            problem_response(
                "create-native-coding-session-turn-failed",
                StatusCode::INTERNAL_SERVER_ERROR,
                "system_error",
                format!("Failed to execute native coding session turn: {error}"),
            )
        })?;

        return Ok((
            StatusCode::CREATED,
            Json({
                let app_admin_state = state.read_app_admin_state();
                if let Ok(Some(detail)) = get_native_session_async(
                    app_admin_state.projects,
                    native_sessions::NativeSessionLookup {
                        session_id: coding_session_id.clone(),
                        engine_id: native_engine_id.clone().or_else(|| {
                            native_sessions::resolve_native_session_engine_id(
                                coding_session_id.as_str(),
                            )
                        }),
                        workspace_id: None,
                        project_id: None,
                    },
                )
                .await
                {
                    let native_turn_runtime_status =
                        runtime_status_for_coding_session_turn_status(turn.status.as_str())
                            .to_owned();
                    let native_turn_activity_at = turn
                        .completed_at
                        .clone()
                        .or_else(|| turn.started_at.clone())
                        .unwrap_or_else(current_session_timestamp);
                    state.publish_coding_session_realtime_event(CodingSessionRealtimeEventInput {
                        event_kind: "coding-session.turn.created",
                        source_surface: "core",
                        workspace_id: detail.summary.workspace_id.clone(),
                        project_id: detail.summary.project_id.clone(),
                        project_root_path: detail.summary.native_cwd.clone(),
                        coding_session_id: detail.summary.id.clone(),
                        coding_session_title: detail.summary.title.clone(),
                        coding_session_status: detail.summary.status.clone(),
                        coding_session_host_mode: detail.summary.host_mode.clone(),
                        coding_session_engine_id: detail.summary.engine_id.clone(),
                        coding_session_model_id: detail.summary.model_id.clone(),
                        coding_session_runtime_status: Some(native_turn_runtime_status.clone()),
                        native_session_id: Some(detail.summary.id.clone()),
                        coding_session_updated_at: Some(native_turn_activity_at.clone()),
                        turn_id: Some(turn.id.clone()),
                    });
                    state.publish_coding_session_realtime_event(CodingSessionRealtimeEventInput {
                        event_kind: "coding-session.updated",
                        source_surface: "core",
                        workspace_id: detail.summary.workspace_id.clone(),
                        project_id: detail.summary.project_id.clone(),
                        project_root_path: detail.summary.native_cwd.clone(),
                        coding_session_id: detail.summary.id.clone(),
                        coding_session_title: detail.summary.title.clone(),
                        coding_session_status: detail.summary.status.clone(),
                        coding_session_host_mode: detail.summary.host_mode.clone(),
                        coding_session_engine_id: detail.summary.engine_id.clone(),
                        coding_session_model_id: detail.summary.model_id.clone(),
                        coding_session_runtime_status: Some(native_turn_runtime_status),
                        native_session_id: Some(detail.summary.id.clone()),
                        coding_session_updated_at: Some(native_turn_activity_at),
                        turn_id: Some(turn.id.clone()),
                    });
                }
                create_envelope("core-create-turn", turn)
            }),
        ));
    }

    if state.projections.session(&coding_session_id).is_none() {
        return Err(problem_response(
            "create-coding-session-turn-session-not-found",
            StatusCode::NOT_FOUND,
            "not_found",
            "Coding session projection was not found.",
        ));
    }
    let project_root_path = state
        .projections
        .session(&coding_session_id)
        .and_then(|session| {
            state
                .projects
                .iter()
                .find(|project| project.id == session.project_id)
                .and_then(|project| project.root_path.as_deref())
                .map(FsPath::new)
                .map(FsPath::to_path_buf)
        });

    let _requested_stream_hint = input.stream;
    let should_stream_turn = true;
    let pending_turn = state
        .projections
        .create_coding_session_turn(&coding_session_id, input, project_root_path.as_deref())
        .map_err(|error| {
            let (status, code) = projection_authority_error_status(error.as_str());
            problem_response(
                "create-coding-session-turn-failed",
                status,
                code,
                format!("Failed to persist coding session turn authority: {error}"),
            )
        })?;
    state.publish_coding_session_realtime_event(CodingSessionRealtimeEventInput {
        event_kind: "coding-session.turn.created",
        source_surface: "core",
        workspace_id: pending_turn.session.workspace_id.clone(),
        project_id: pending_turn.session.project_id.clone(),
        project_root_path: None,
        coding_session_id: pending_turn.session.id.clone(),
        coding_session_title: pending_turn.session.title.clone(),
        coding_session_status: pending_turn.session.status.clone(),
        coding_session_host_mode: pending_turn.session.host_mode.clone(),
        coding_session_engine_id: pending_turn.session.engine_id.clone(),
        coding_session_model_id: pending_turn.session.model_id.clone(),
        coding_session_runtime_status: Some("streaming".to_owned()),
        native_session_id: pending_turn
            .native_session_id
            .clone()
            .or_else(|| pending_turn.session.native_session_id.clone()),
        coding_session_updated_at: Some(
            pending_turn
                .turn
                .started_at
                .clone()
                .unwrap_or_else(current_session_timestamp),
        ),
        turn_id: Some(pending_turn.turn.id.clone()),
    });

    let background_state = state.clone();
    let background_turn = pending_turn.clone();
    tokio::spawn(async move {
        let turn_request = native_sessions::NativeSessionTurnRequest {
            engine_id: background_turn.session.engine_id.clone(),
            model_id: background_turn.session.model_id.clone(),
            native_session_id: background_turn.native_session_id.clone(),
            request_kind: background_turn.turn.request_kind.clone(),
            input_summary: background_turn.turn.input_summary.clone(),
            ide_context: to_native_session_turn_ide_context(background_turn.ide_context.as_ref()),
            working_directory: background_turn.working_directory.clone(),
            config: build_native_session_turn_config(background_turn.options.as_ref()),
        };

        let streaming_state = background_state.clone();
        let streaming_turn = background_turn.clone();
        let completion_result = match tokio::task::spawn_blocking(move || {
            if !should_stream_turn {
                return native_sessions::execute_native_session_turn(&turn_request);
            }

            native_sessions::execute_native_session_turn_with_events(&turn_request, |event| {
                let resolved_native_session_id = event
                    .native_session_id
                    .as_deref()
                    .or(streaming_turn.native_session_id.as_deref());
                let stream_event = streaming_state
                    .projections
                    .append_coding_session_stream_event(
                        &streaming_turn,
                        event.kind.as_str(),
                        event.role.as_str(),
                        event.content_delta.as_str(),
                        event.payload.as_ref(),
                        resolved_native_session_id,
                    )?;
                if let Some(stream_event) = stream_event {
                    streaming_state.publish_streaming_coding_session_event_realtime_event(
                        &streaming_turn,
                        &stream_event,
                    );
                }
                Ok(())
            })
        })
        .await
        {
            Ok(Ok(native_turn_result)) => {
                let resolved_native_session_id = native_turn_result
                    .native_session_id
                    .as_deref()
                    .or(background_turn.native_session_id.as_deref());
                background_state.projections.complete_coding_session_turn(
                    &background_turn,
                    native_turn_result.assistant_content.as_str(),
                    native_turn_result.commands.as_deref(),
                    resolved_native_session_id,
                )
            }
            Ok(Err(error)) => background_state.projections.fail_coding_session_turn(
                &background_turn,
                error.as_str(),
                background_turn.native_session_id.as_deref(),
            ),
            Err(error) => background_state.projections.fail_coding_session_turn(
                &background_turn,
                format!("Failed to join native coding session turn task: {error}").as_str(),
                background_turn.native_session_id.as_deref(),
            ),
        };

        match completion_result {
            Ok(finalized_turn) => {
                if let Some(updated_session) = background_state
                    .projections
                    .session(finalized_turn.turn.coding_session_id.as_str())
                {
                    for event in &finalized_turn.events {
                        background_state.publish_finalized_coding_session_event_realtime_event(
                            &background_turn,
                            &updated_session,
                            event,
                        );
                    }
                }
            }
            Err(error) => {
                eprintln!(
                    "background coding session turn {} failed to persist completion: {error}",
                    background_turn.turn.id
                );
            }
        }
    });

    Ok((
        StatusCode::CREATED,
        Json(create_envelope("core-create-turn", pending_turn.turn)),
    ))
}

async fn core_submit_approval_decision(
    State(state): State<AppState>,
    AxumPath(approval_id): AxumPath<String>,
    Json(request): Json<SubmitApprovalDecisionRequest>,
) -> Result<
    Json<ApiEnvelope<ApprovalDecisionPayload>>,
    (StatusCode, Json<ApiEnvelope<ProblemDetailsPayload>>),
> {
    let input = SubmitApprovalDecisionInput::try_from(request).map_err(|message| {
        problem_response(
            "submit-approval-decision-invalid",
            StatusCode::BAD_REQUEST,
            "argument_invalid",
            message,
        )
    })?;

    if !state.projections.has_approval(&approval_id) {
        return Err(problem_response(
            "submit-approval-decision-not-found",
            StatusCode::NOT_FOUND,
            "not_found",
            "Approval checkpoint was not found.",
        ));
    }

    state
        .submit_live_provider_approval_decision(&approval_id, &input)
        .map_err(|error| {
            problem_response(
                "submit-approval-decision-provider-reply-failed",
                StatusCode::BAD_GATEWAY,
                "provider_reply_failed",
                format!("Failed to submit live provider approval decision: {error}"),
            )
        })?;

    let approval = state
        .projections
        .submit_approval_decision(&approval_id, input)
        .map_err(|error| {
            problem_response(
                "submit-approval-decision-failed",
                StatusCode::INTERNAL_SERVER_ERROR,
                "system_error",
                format!("Failed to persist approval authority: {error}"),
            )
        })?;
    state.publish_projection_coding_session_event_realtime_event(
        approval.payload.coding_session_id.as_str(),
        &approval.event,
    );

    Ok(Json(create_envelope(
        "core-approval-decision",
        approval.payload,
    )))
}

async fn core_submit_user_question_answer(
    State(state): State<AppState>,
    AxumPath(question_id): AxumPath<String>,
    Json(request): Json<SubmitUserQuestionAnswerRequest>,
) -> Result<
    Json<ApiEnvelope<UserQuestionAnswerPayload>>,
    (StatusCode, Json<ApiEnvelope<ProblemDetailsPayload>>),
> {
    let input = SubmitUserQuestionAnswerInput::try_from(request).map_err(|message| {
        problem_response(
            "submit-user-question-answer-invalid",
            StatusCode::BAD_REQUEST,
            "argument_invalid",
            message,
        )
    })?;

    if !state.projections.has_user_question(&question_id) {
        return Err(problem_response(
            "submit-user-question-answer-not-found",
            StatusCode::NOT_FOUND,
            "not_found",
            "User question was not found.",
        ));
    }

    state
        .submit_live_provider_user_question_answer(&question_id, &input)
        .map_err(|error| {
            problem_response(
                "submit-user-question-answer-provider-reply-failed",
                StatusCode::BAD_GATEWAY,
                "provider_reply_failed",
                format!("Failed to submit live provider user question answer: {error}"),
            )
        })?;

    let answer = state
        .projections
        .submit_user_question_answer(&question_id, input)
        .map_err(|error| {
            if error.contains("user question") && error.contains("was not found") {
                return problem_response(
                    "submit-user-question-answer-not-found",
                    StatusCode::NOT_FOUND,
                    "not_found",
                    "User question was not found.",
                );
            }

            problem_response(
                "submit-user-question-answer-failed",
                StatusCode::INTERNAL_SERVER_ERROR,
                "system_error",
                format!("Failed to persist user question authority: {error}"),
            )
        })?;
    state.publish_projection_coding_session_event_realtime_event(
        answer.payload.coding_session_id.as_str(),
        &answer.event,
    );

    Ok(Json(create_envelope(
        "core-user-question-answer",
        answer.payload,
    )))
}

async fn core_session_events(
    State(state): State<AppState>,
    AxumPath(coding_session_id): AxumPath<String>,
) -> Result<
    Json<ApiListEnvelope<CodingSessionEventPayload>>,
    (StatusCode, Json<ApiEnvelope<ProblemDetailsPayload>>),
> {
    if let Some(snapshot) = state.projections.session_snapshot(&coding_session_id) {
        if let Some(session) = snapshot.session.as_ref() {
            if let Some(detail) = read_projection_native_session_detail(
                state.clone(),
                session.clone(),
                snapshot.clone(),
            )
            .await
            .map_err(|error| {
                problem_response(
                    "native-session-events-read-failed",
                    StatusCode::INTERNAL_SERVER_ERROR,
                    "system_error",
                    format!("Failed to read native session events: {error}"),
                )
            })? {
                return Ok(Json(create_list_envelope(
                    "core-session-events",
                    build_projection_session_events_with_native_detail(
                        &snapshot,
                        &detail,
                        coding_session_id.as_str(),
                    ),
                )));
            }
        }

        return Ok(Json(create_list_envelope(
            "core-session-events",
            snapshot.events.clone(),
        )));
    }

    let app_admin_state = state.read_app_admin_state();
    let native_engine_id =
        native_sessions::resolve_native_session_engine_id(coding_session_id.as_str());
    let detail = get_native_session_async(
        app_admin_state.projects,
        native_sessions::NativeSessionLookup {
            session_id: coding_session_id,
            engine_id: native_engine_id,
            workspace_id: None,
            project_id: None,
        },
    )
    .await
    .map_err(|error| {
        problem_response(
            "native-session-events-read-failed",
            StatusCode::INTERNAL_SERVER_ERROR,
            "system_error",
            format!("Failed to read native session events: {error}"),
        )
    })?
    .ok_or_else(|| {
        problem_response(
            "session-events-not-found",
            StatusCode::NOT_FOUND,
            "not_found",
            "Coding session projection was not found.",
        )
    })?;

    Ok(Json(create_list_envelope(
        "core-session-events",
        build_native_session_events(&detail),
    )))
}

async fn resolve_fork_source_session_and_events(
    state: AppState,
    coding_session_id: &str,
) -> Result<(CodingSessionPayload, Vec<CodingSessionEventPayload>), String> {
    if let Some(session) = state.projections.session(coding_session_id) {
        if let Some(snapshot) = state.projections.session_snapshot(coding_session_id) {
            if let Some(detail) = read_projection_native_session_detail(
                state.clone(),
                session.clone(),
                snapshot.clone(),
            )
            .await?
            {
                return Ok((
                    overlay_projection_session_with_native_summary(&session, &detail.summary),
                    build_projection_session_events_with_native_detail(
                        &snapshot,
                        &detail,
                        coding_session_id,
                    ),
                ));
            }

            return Ok((session, snapshot.events));
        }

        return Ok((session, Vec::new()));
    }

    if !is_native_coding_session_id(coding_session_id) {
        return Err(format!("coding session {coding_session_id} was not found"));
    }

    let app_admin_state = state.read_app_admin_state();
    let detail = get_native_session_async(
        app_admin_state.projects,
        native_sessions::NativeSessionLookup {
            session_id: coding_session_id.to_owned(),
            engine_id: native_sessions::resolve_native_session_engine_id(coding_session_id),
            workspace_id: None,
            project_id: None,
        },
    )
    .await?
    .ok_or_else(|| format!("coding session {coding_session_id} was not found"))?;

    Ok((
        build_coding_session_payload_from_native_summary(&detail.summary),
        build_native_session_events(&detail),
    ))
}

